package com.ayush.springtest; import org.junit.jupiter.params.ParameterizedTest; import org.junit.jupiter.params.provider.CsvSource; import static org.junit.jupiter.api.Assertions.*; class ParameterizedCalculatorTest { @ParameterizedTest @CsvSource({"1,2,3","5,7,12","10,20,30"}) void addMultipleInputs(int a,int b,int expected){ assertEquals(expected, new CalculatorService().add(a,b)); }}